import java.util.concurrent.CompletableFuture;
import java.util.List;

public class ReportService {
    public CompletableFuture<List<String>> loadReport(String userId) {
        return CompletableFuture.supplyAsync(() -> fetchLogs(userId))
            .thenCombine(CompletableFuture.supplyAsync(() -> fetchMetrics(userId)), 
                (logs, metrics) -> List.of(logs, metrics));
    }
}
